\DeclareMathOperator{\tr}{\text{tr}}
\DeclareMathOperator{\diag}{\text{diag}}
\begin{align}
\chi^2_{独立モデル} &= \tr( \diag(S)^{-1} S) - \log |(\diag(S))^{-1} S| - p\\
                    &= p - \log |(\diag(S))^{-1} S| - p\\
                    &= - \log |(\diag(S))^{-1} S|\\
df_{独立モデル} &= \frac{1}{2} p(p - 1)
\end{align}
